JObject:
(preserveContent: true);
                var messages = body?["messages"] as JArray;
                if (messages == null) return "";
                // Get the last user message (most recent input)
                var lastUser = messages.Reverse()
                                       .FirstOrDefault(m => (string)m["role"] == "user");
