      @($"{(string)context.Variables.GetValueOrDefault("content-safety-endpoint")}/contentsafety/text:analyze?api-version=2023-10-01")
      POST

        @((string)context.Variables.GetValueOrDefault("content-safety-key"))


        application/json

      @{
        return new JObject(
          new JProperty("text", (string)context.Variables["user_message"]),
          new JProperty("categories", new JArray("Hate", "Sexual", "SelfHarm", "Violence")),
          new JProperty("outputType", "FourSeverityLevels")
        ).ToString();
      }



    <set-variable name="safety_threshold"
                  value="@{
                    var tenantId = (string)context.Variables.GetValueOrDefault("tenant_id", "unknown");
                    var perTenantKey = "content-safety-threshold-" + tenantId;
                    var perTenant = context.Variables.GetValueOrDefault(perTenantKey);
                    var defaultThreshold = context.Variables.GetValueOrDefault("content-safety-threshold-default") ?? "4";
                    return int.Parse(perTenant ?? defaultThreshold);
                  }" />


    <set-variable name="max_severity"
                  value="@{
                    var response = (IResponse)context.Variables.GetValueOrDefault("safety_response");
                    if (response == null || response.StatusCode != 200) {
                      // If Content Safety call failed, fail open (allow) and log; don't break tenant traffic on Content Safety outage
                      return 0;
                    }
                    var body = response.Body.As(preserveContent: true);
                    var analysis = body?["categoriesAnalysis"] as JArray;
                    if (analysis == null) return 0;
                    int maxSev = 0;
                    foreach (var cat in analysis) {
                      var sev = (int?)cat["severity"] ?? 0;
                      if (sev > maxSev) maxSev = sev;
                    }
                    return maxSev;
                  }" />







          @{
            return new JObject(
              new JProperty("timestamp", DateTime.UtcNow.ToString("o")),
              new JProperty("event_type", "content_safety_violation"),
              new JProperty("tenant_id", (string)context.Variables["tenant_id"]),
              new JProperty("correlation_id", (string)context.Variables["correlation_id"]),
              new JProperty("max_severity", (int)context.Variables["max_severity"]),
              new JProperty("threshold", (int)context.Variables["safety_threshold"])
            ).ToString();
          }





            application/json

          @{
            return new JObject(
              new JProperty("error", "content_safety_violation"),
              new JProperty("tenant_id", (string)context.Variables["tenant_id"]),
              new JProperty("severity", (int)context.Variables["max_severity"]),
              new JProperty("threshold", (int)context.Variables["safety_threshold"]),
              new JProperty("correlation_id", (string)context.Variables["correlation_id"]),
              new JProperty("message", "The request was blocked by content safety policy. See correlation_id for support reference.")
            ).ToString();
          }
